model = Sketchup.active_model
sel = model.selection.to_a
explodable = sel.select { |e| e.respond_to?(:explode) }
if explodable.empty?
  { 'ok' => false, 'error' => 'no selected groups or components to explode' }
else
  model.start_operation('AWARE explode', true)
  exploded = 0
  explodable.each { |e| e.explode; exploded += 1 }
  model.commit_operation
  { 'ok' => true, 'exploded' => exploded }
end
